'use client';

import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { ArrowLeft, Zap, Plus, Calendar, Loader2, Pause, Play, Trash2 } from "lucide-react";
import { useRouter } from "next/navigation";
import { useRecurringTransactions } from "@/hooks/useRecurringTransactions";
import { formatCurrency } from "@/lib/utils";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import { Badge } from "@/components/ui/badge";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { useState } from "react";

const frequencyLabels: Record<string, string> = {
    diaria: 'Diária',
    semanal: 'Semanal',
    quinzenal: 'Quinzenal',
    mensal: 'Mensal',
    bimestral: 'Bimestral',
    trimestral: 'Trimestral',
    semestral: 'Semestral',
    anual: 'Anual',
};

export default function FinancialRecurringPage() {
    const router = useRouter();
    const {
        recurringTransactions,
        isLoading,
        deleteRecurringTransaction,
        updateRecurringTransaction,
    } = useRecurringTransactions();
    const [deleteId, setDeleteId] = useState<string | null>(null);

    const handleToggleActive = async (id: string, currentActive: boolean) => {
        await updateRecurringTransaction.mutateAsync({
            id,
            updates: { is_active: !currentActive },
        });
    };

    const handleDelete = async () => {
        if (deleteId) {
            await deleteRecurringTransaction.mutateAsync(deleteId);
            setDeleteId(null);
        }
    };

    if (isLoading) {
        return (
            <div className="flex items-center justify-center h-64">
                <Loader2 className="h-8 w-8 animate-spin text-orange-500" />
            </div>
        );
    }

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex items-center gap-4">
                <Button variant="ghost" size="icon" onClick={() => router.push('/financial')}>
                    <ArrowLeft className="h-5 w-5" />
                </Button>
                <div className="flex-1">
                    <h1 className="text-2xl font-bold text-foreground flex items-center gap-2">
                        <Zap className="h-6 w-6 text-orange-500" />
                        Transações Recorrentes
                    </h1>
                    <p className="text-muted-foreground">Gerencie receitas e despesas que se repetem automaticamente</p>
                </div>
                <Button className="bg-orange-500 hover:bg-orange-600 gap-2">
                    <Plus className="h-4 w-4" />
                    Nova Recorrência
                </Button>
            </div>

            {/* List */}
            {recurringTransactions.length === 0 ? (
                <Card className="border-dashed">
                    <CardContent className="p-8 text-center">
                        <Zap className="h-12 w-12 mx-auto mb-4 text-muted-foreground/50" />
                        <h3 className="text-lg font-medium mb-2">Nenhuma transação recorrente</h3>
                        <p className="text-muted-foreground mb-4">
                            Crie transações recorrentes para automatizar lançamentos que se repetem.
                        </p>
                    </CardContent>
                </Card>
            ) : (
                <div className="grid gap-4">
                    {recurringTransactions.map((recurring) => (
                        <Card key={recurring.id} className="hover:shadow-md transition-shadow">
                            <CardContent className="p-4">
                                <div className="flex items-center justify-between">
                                    <div className="flex items-center gap-4">
                                        <div className={`p-2 rounded-lg ${recurring.is_active ? 'bg-orange-500/10' : 'bg-muted'}`}>
                                            <Zap className={`h-5 w-5 ${recurring.is_active ? 'text-orange-500' : 'text-muted-foreground'}`} />
                                        </div>
                                        <div>
                                            <p className="font-medium">
                                                {recurring.template_transaction?.description || 'Transação Recorrente'}
                                            </p>
                                            <div className="flex items-center gap-2 text-sm text-muted-foreground">
                                                <Calendar className="h-3 w-3" />
                                                <span>
                                                    Próxima: {format(new Date(recurring.next_occurrence), "dd/MM/yyyy", { locale: ptBR })}
                                                </span>
                                                <Badge variant="outline">
                                                    {frequencyLabels[recurring.frequency] || recurring.frequency}
                                                </Badge>
                                            </div>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-4">
                                        <p className="font-bold text-lg">
                                            {formatCurrency(recurring.template_transaction?.amount || 0)}
                                        </p>
                                        <div className="flex items-center gap-1">
                                            <Button
                                                variant="ghost"
                                                size="sm"
                                                onClick={() => handleToggleActive(recurring.id, recurring.is_active)}
                                            >
                                                {recurring.is_active ? (
                                                    <Pause className="h-4 w-4 text-amber-500" />
                                                ) : (
                                                    <Play className="h-4 w-4 text-emerald-500" />
                                                )}
                                            </Button>
                                            <Button
                                                variant="ghost"
                                                size="sm"
                                                onClick={() => setDeleteId(recurring.id)}
                                            >
                                                <Trash2 className="h-4 w-4 text-red-500" />
                                            </Button>
                                        </div>
                                    </div>
                                </div>
                            </CardContent>
                        </Card>
                    ))}
                </div>
            )}

            {/* Delete Confirmation */}
            <AlertDialog open={!!deleteId} onOpenChange={(open) => !open && setDeleteId(null)}>
                <AlertDialogContent>
                    <AlertDialogHeader>
                        <AlertDialogTitle>Excluir transação recorrente?</AlertDialogTitle>
                        <AlertDialogDescription>
                            Esta ação não pode ser desfeita. A transação recorrente será removida permanentemente.
                        </AlertDialogDescription>
                    </AlertDialogHeader>
                    <AlertDialogFooter>
                        <AlertDialogCancel>Cancelar</AlertDialogCancel>
                        <AlertDialogAction
                            className="bg-red-500 hover:bg-red-600"
                            onClick={handleDelete}
                        >
                            Excluir
                        </AlertDialogAction>
                    </AlertDialogFooter>
                </AlertDialogContent>
            </AlertDialog>
        </div>
    );
}
