'use client';

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { createClient } from '@/lib/supabase/client';
import { useUserProfile } from './useUserProfile';
import { toast } from '@/hooks/use-toast';
import {
    FinancialRecurringTransaction,
    FinancialRecurringTransactionInsert,
    FinancialRecurringTransactionUpdate,
    FinancialRecurringTransactionWithTemplate,
    RecurrenceFrequency,
} from '@/types/financial';

export function useRecurringTransactions() {
    const supabase = createClient();
    const queryClient = useQueryClient();
    const { user, profile } = useUserProfile();

    // Query for recurring transactions
    const {
        data: recurringTransactions = [],
        isLoading,
        error,
        refetch,
    } = useQuery({
        queryKey: ['recurring-transactions', user?.id],
        queryFn: async (): Promise<FinancialRecurringTransactionWithTemplate[]> => {
            if (!user?.id) return [];

            const { data, error } = await supabase
                .from('financial_recurring_transactions')
                .select(`
                    *,
                    template_transaction:financial_transactions!template_transaction_id(*)
                `)
                .order('next_occurrence', { ascending: true }) as {
                    data: FinancialRecurringTransactionWithTemplate[] | null;
                    error: Error | null;
                };

            if (error) {
                console.error('Error fetching recurring transactions:', error);
                throw error;
            }

            return data || [];
        },
        enabled: !!user?.id,
        staleTime: 2 * 60 * 1000,
        refetchOnMount: false,
        refetchOnWindowFocus: false,
    });

    // Create recurring transaction mutation
    const createRecurringTransaction = useMutation({
        mutationFn: async (data: {
            template_transaction_id?: string | null;
            frequency: RecurrenceFrequency;
            amount: number;
            type: string;
            description?: string | null;
            account_id?: string | null;
            category_id?: string | null;
            next_date: string;
            is_active?: boolean;
        }) => {
            if (!user?.id) throw new Error('User not authenticated');

            const insertData: FinancialRecurringTransactionInsert = {
                user_id: user.id,
                organization_id: profile?.organization_id || null,
                template_transaction_id: data.template_transaction_id || null,
                frequency: data.frequency,
                start_date: data.next_date,
                next_occurrence: data.next_date,
                is_active: data.is_active ?? true,
            };

            const { data: result, error } = await supabase
                .from('financial_recurring_transactions')
                .insert(insertData as never)
                .select()
                .single();

            if (error) throw error;
            return result as FinancialRecurringTransaction;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['recurring-transactions'] });
            toast({
                title: 'Sucesso',
                description: 'Transação recorrente criada com sucesso!',
            });
        },
        onError: (error: Error) => {
            console.error('Error creating recurring transaction:', error);
            toast({
                title: 'Erro',
                description: error.message,
                variant: 'destructive',
            });
        },
    });

    // Update recurring transaction mutation
    const updateRecurringTransaction = useMutation({
        mutationFn: async ({
            id,
            updates,
        }: {
            id: string;
            updates: FinancialRecurringTransactionUpdate;
        }) => {
            const { data, error } = await supabase
                .from('financial_recurring_transactions')
                .update(updates as never)
                .eq('id', id)
                .select()
                .single();

            if (error) throw error;
            return data as FinancialRecurringTransaction;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['recurring-transactions'] });
            toast({
                title: 'Sucesso',
                description: 'Transação recorrente atualizada com sucesso!',
            });
        },
        onError: (error: Error) => {
            console.error('Error updating recurring transaction:', error);
            toast({
                title: 'Erro',
                description: error.message,
                variant: 'destructive',
            });
        },
    });

    // Delete recurring transaction mutation
    const deleteRecurringTransaction = useMutation({
        mutationFn: async (id: string) => {
            const { error } = await supabase
                .from('financial_recurring_transactions')
                .delete()
                .eq('id', id);

            if (error) throw error;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['recurring-transactions'] });
            toast({
                title: 'Sucesso',
                description: 'Transação recorrente removida com sucesso!',
            });
        },
        onError: (error: Error) => {
            console.error('Error deleting recurring transaction:', error);
            toast({
                title: 'Erro',
                description: error.message,
                variant: 'destructive',
            });
        },
    });

    // Execute recurring transaction (advance to next occurrence)
    const executeRecurringTransaction = useMutation({
        mutationFn: async (id: string) => {
            // Fetch the recurring transaction
            const { data: recurring, error: fetchError } = await supabase
                .from('financial_recurring_transactions')
                .select('*')
                .eq('id', id)
                .single() as { data: FinancialRecurringTransaction | null; error: Error | null };

            if (fetchError) throw new Error(fetchError.message);
            if (!recurring) throw new Error('Transação recorrente não encontrada');

            // Calculate next occurrence based on frequency
            const nextOccurrence = new Date(recurring.next_occurrence);

            switch (recurring.frequency) {
                case 'diaria':
                    nextOccurrence.setDate(nextOccurrence.getDate() + 1);
                    break;
                case 'semanal':
                    nextOccurrence.setDate(nextOccurrence.getDate() + 7);
                    break;
                case 'quinzenal':
                    nextOccurrence.setDate(nextOccurrence.getDate() + 15);
                    break;
                case 'mensal':
                    nextOccurrence.setMonth(nextOccurrence.getMonth() + 1);
                    break;
                case 'bimestral':
                    nextOccurrence.setMonth(nextOccurrence.getMonth() + 2);
                    break;
                case 'trimestral':
                    nextOccurrence.setMonth(nextOccurrence.getMonth() + 3);
                    break;
                case 'semestral':
                    nextOccurrence.setMonth(nextOccurrence.getMonth() + 6);
                    break;
                case 'anual':
                    nextOccurrence.setFullYear(nextOccurrence.getFullYear() + 1);
                    break;
                default:
                    nextOccurrence.setMonth(nextOccurrence.getMonth() + 1);
                    break;
            }

            const { error: updateError } = await supabase
                .from('financial_recurring_transactions')
                .update({
                    next_occurrence: nextOccurrence.toISOString().split('T')[0],
                } as never)
                .eq('id', id);

            if (updateError) throw new Error(updateError.message);

            return recurring;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['recurring-transactions'] });
            queryClient.invalidateQueries({ queryKey: ['financial-transactions'] });
            queryClient.invalidateQueries({ queryKey: ['financial-metrics'] });
            toast({
                title: 'Sucesso',
                description: 'Transação recorrente executada com sucesso!',
            });
        },
        onError: (error: Error) => {
            console.error('Error executing recurring transaction:', error);
            toast({
                title: 'Erro',
                description: error.message,
                variant: 'destructive',
            });
        },
    });

    // Filter active and inactive
    const activeTransactions = recurringTransactions.filter((t) => t.is_active);
    const inactiveTransactions = recurringTransactions.filter((t) => !t.is_active);

    // Get upcoming (next 7 days)
    const upcomingTransactions = activeTransactions.filter((t) => {
        const next = new Date(t.next_occurrence);
        const today = new Date();
        const weekFromNow = new Date(today.getTime() + 7 * 24 * 60 * 60 * 1000);
        return next >= today && next <= weekFromNow;
    });

    return {
        recurringTransactions,
        activeTransactions,
        inactiveTransactions,
        upcomingTransactions,
        isLoading,
        error,
        refetch,
        createRecurringTransaction,
        updateRecurringTransaction,
        deleteRecurringTransaction,
        executeRecurringTransaction,
    };
}
